CREATE PROC [dbo].[GM_JumpingCharDA_UpdateCheckedServerSetting]
		@server_id				int,
		@is_special_server		tinyint,
		@start_date				datetime,
		@end_date				datetime,
		@max_creation_count		int,
		@required_char_level	int,
		@is_deleted				tinyint,
		@login_id				nvarchar(30),
		@login_nm				nvarchar(30)
AS
BEGIN
	UPDATE	jumping_character_config
	SET		start_date = @start_date,
			end_date = @end_date,
			max_creation_count = @max_creation_count,
			required_char_level = @required_char_level,
			is_deleted = @is_deleted,
			login_id = @login_id,
			login_nm = @login_nm,
			reg_date = GETDATE()
	WHERE	server_id = @server_id
	IF (@@ROWCOUNT < 1)
	BEGIN
		INSERT INTO jumping_character_config (server_id, is_special_server, start_date, end_date, max_creation_count, required_char_level, is_deleted, login_id, login_nm, reg_date)
		VALUES (@server_id, @is_special_server, @start_date, @end_date, @max_creation_count, @required_char_level, @is_deleted, @login_id, @login_nm, GETDATE())
	END
END

